import type { Holding, PriceMap } from './types'

const DATA_DIR = import.meta.dir + '/data'
const HOLDINGS_PATH = `${DATA_DIR}/holdings.json`
const PRICES_PATH = `${DATA_DIR}/prices.json`

export const loadHoldings = async (): Promise<Holding[]> => {
  const file = Bun.file(HOLDINGS_PATH)
  if (!(await file.exists())) return []
  return file.json()
}

export const saveHoldings = async (holdings: Holding[]): Promise<void> => {
  await Bun.write(HOLDINGS_PATH, JSON.stringify(holdings, null, 2))
}

export const loadPrices = async (): Promise<PriceMap> => {
  const file = Bun.file(PRICES_PATH)
  if (!(await file.exists())) return {}
  return file.json()
}

export const savePrices = async (prices: PriceMap): Promise<void> => {
  await Bun.write(PRICES_PATH, JSON.stringify(prices, null, 2))
}

import type { Holding } from './types'
import { loadHoldings, saveHoldings, loadPrices, savePrices } from './store'

export const addHolding = async (symbol: string, amount: number, purchasePrice: number): Promise<Holding> => {
  const holdings = await loadHoldings()
  const prices = await loadPrices()
  const id = `${symbol.toUpperCase()}-${Date.now()}`
  const holding: Holding = {
    id,
    symbol: symbol.toUpperCase(),
    amount,
    purchasePrice,
  }
  holdings.push(holding)
  await saveHoldings(holdings)

  if (prices[holding.symbol] === undefined) {
    prices[holding.symbol] = purchasePrice
    await savePrices(prices)
  }

  return holding
}

export const removeHolding = async (id: string): Promise<boolean> => {
  const holdings = await loadHoldings()
  const idx = holdings.findIndex((h) => h.id === id)
  if (idx === -1) return false
  holdings.splice(idx, 1)
  await saveHoldings(holdings)
  return true
}

export const updatePrice = async (symbol: string, price: number): Promise<void> => {
  const prices = await loadPrices()
  prices[symbol.toUpperCase()] = price
  await savePrices(prices)
}

import type { PortfolioEntry, PortfolioSummary } from './types'
import { loadHoldings, loadPrices } from './store'

export const getPortfolioSummary = async (): Promise<PortfolioSummary> => {
  const holdings = await loadHoldings()
  const prices = await loadPrices()

  const entries: PortfolioEntry[] = holdings.map((holding) => {
    const currentPrice = prices[holding.symbol] ?? holding.purchasePrice
    const currentValue = holding.amount * currentPrice
    const costBasis = holding.amount * holding.purchasePrice
    const gainLoss = currentValue - costBasis
    const gainLossPercent = costBasis !== 0 ? (gainLoss / costBasis) * 100 : 0

    return {
      holding,
      currentPrice,
      currentValue,
      costBasis,
      gainLoss,
      gainLossPercent,
      allocationPercent: 0,
    }
  })

  const totalValue = entries.reduce((sum, e) => sum + e.currentValue, 0)
  const totalCost = entries.reduce((sum, e) => sum + e.costBasis, 0)
  const totalGainLoss = totalValue - totalCost
  const totalGainLossPercent = totalCost !== 0 ? (totalGainLoss / totalCost) * 100 : 0

  for (const entry of entries) {
    entry.allocationPercent = totalValue !== 0 ? (entry.currentValue / totalValue) * 100 : 0
  }

  return { entries, totalValue, totalCost, totalGainLoss, totalGainLossPercent }
}

import { h } from 'plaited'
import type { PortfolioEntry } from './types'

const COLORS = [
  '#f7931a', // BTC orange
  '#627eea', // ETH blue
  '#26a17b', // USDT green
  '#2775ca', // USDC blue
  '#e84142', // AVAX red
  '#8247e5', // MATIC purple
  '#00d395', // COMP green
  '#f0b90b', // BNB yellow
  '#e6007a', // DOT pink
  '#dc1fff', // SOL purple
  '#345d9d', // LINK blue
  '#cf202f', // ADA red
]

type SliceData = {
  percent: number
  color: string
  label: string
}

const describeArc = (cx: number, cy: number, r: number, startAngle: number, endAngle: number): string => {
  const start = polarToCartesian(cx, cy, r, endAngle)
  const end = polarToCartesian(cx, cy, r, startAngle)
  const largeArcFlag = endAngle - startAngle > 180 ? 1 : 0

  return [
    `M ${cx} ${cy}`,
    `L ${start.x} ${start.y}`,
    `A ${r} ${r} 0 ${largeArcFlag} 0 ${end.x} ${end.y}`,
    'Z',
  ].join(' ')
}

const polarToCartesian = (cx: number, cy: number, r: number, angleDeg: number) => {
  const angleRad = ((angleDeg - 90) * Math.PI) / 180
  return {
    x: cx + r * Math.cos(angleRad),
    y: cy + r * Math.sin(angleRad),
  }
}

export const renderPieChart = (entries: PortfolioEntry[]): string => {
  if (entries.length === 0) {
    return h(
      'div',
      { style: 'text-align:center;color:#888;padding:20px' },
      h('p', {}, 'No holdings to display'),
    ) as string
  }

  const slices: SliceData[] = entries.map((entry, i) => ({
    percent: entry.allocationPercent,
    color: COLORS[i % COLORS.length],
    label: entry.holding.symbol,
  }))

  const cx = 100
  const cy = 100
  const r = 90

  let currentAngle = 0
  const paths: string[] = []

  for (const slice of slices) {
    if (slice.percent <= 0) continue

    const sliceAngle = (slice.percent / 100) * 360

    if (slice.percent >= 99.99) {
      paths.push(
        h('circle', { cx: String(cx), cy: String(cy), r: String(r), fill: slice.color }) as string,
      )
    } else {
      const pathD = describeArc(cx, cy, r, currentAngle, currentAngle + sliceAngle)
      paths.push(h('path', { d: pathD, fill: slice.color }) as string)
    }
    currentAngle += sliceAngle
  }

  const legend = slices
    .filter((s) => s.percent > 0)
    .map(
      (s) =>
        h(
          'div',
          { style: 'display:flex;align-items:center;gap:6px;margin:2px 0' },
          h('span', {
            style: `display:inline-block;width:12px;height:12px;border-radius:2px;background:${s.color}`,
          }),
          h('span', { style: 'font-size:13px' }, `${s.label} ${s.percent.toFixed(1)}%`),
        ) as string,
    )

  return h(
    'div',
    { style: 'display:flex;align-items:center;gap:24px;flex-wrap:wrap;justify-content:center' },
    h(
      'svg',
      { viewBox: '0 0 200 200', width: '200', height: '200' },
      ...paths,
    ),
    h('div', {}, ...legend),
  ) as string
}

import { addHolding, removeHolding, updatePrice } from './holdings'
import { getPortfolioSummary } from './portfolio'
import { renderPortfolio } from './ui'

type ActionResult = {
  html: string
  status: number
}

type AddHoldingPayload = {
  symbol: string
  amount: string | number
  purchasePrice: string | number
}

type UpdatePricePayload = {
  symbol: string
  price: string | number
}

type RemovePayload = {
  id: string
}

const renderPage = async (): Promise<string> => {
  const summary = await getPortfolioSummary()
  return renderPortfolio(summary)
}

export const handleAddHolding = async (payload: AddHoldingPayload): Promise<ActionResult> => {
  const symbol = String(payload.symbol).trim()
  const amount = Number(payload.amount)
  const purchasePrice = Number(payload.purchasePrice)

  if (!symbol || isNaN(amount) || amount <= 0 || isNaN(purchasePrice) || purchasePrice < 0) {
    return { html: '<p style="color:red">Invalid input. Provide symbol, positive amount, and non-negative price.</p>', status: 400 }
  }

  await addHolding(symbol, amount, purchasePrice)
  const html = await renderPage()
  return { html, status: 200 }
}

export const handleUpdatePrice = async (payload: UpdatePricePayload): Promise<ActionResult> => {
  const symbol = String(payload.symbol).trim()
  const price = Number(payload.price)

  if (!symbol || isNaN(price) || price < 0) {
    return { html: '<p style="color:red">Invalid input. Provide symbol and non-negative price.</p>', status: 400 }
  }

  await updatePrice(symbol, price)
  const html = await renderPage()
  return { html, status: 200 }
}

export const handleRemoveHolding = async (payload: RemovePayload): Promise<ActionResult> => {
  const { id } = payload
  if (!id) {
    return { html: '<p style="color:red">Missing holding id.</p>', status: 400 }
  }

  await removeHolding(id)
  const html = await renderPage()
  return { html, status: 200 }
}

export const handleView = async (): Promise<ActionResult> => {
  const html = await renderPage()
  return { html, status: 200 }
}

const server = Bun.serve({
  port: Number(process.env.PORT) || 3000,
  fetch: async (req) => {
    const url = new URL(req.url)
    const path = url.pathname

    if (req.method === 'GET' && path === '/') {
      const result = await handleView()
      return new Response(result.html, {
        status: result.status,
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      })
    }

    if (req.method === 'POST' && path === '/holdings') {
      const body = await req.json() as AddHoldingPayload
      const result = await handleAddHolding(body)
      return new Response(result.html, {
        status: result.status,
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      })
    }

    if (req.method === 'POST' && path === '/prices') {
      const body = await req.json() as UpdatePricePayload
      const result = await handleUpdatePrice(body)
      return new Response(result.html, {
        status: result.status,
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      })
    }

    if (req.method === 'DELETE' && path.startsWith('/holdings/')) {
      const id = path.slice('/holdings/'.length)
      const result = await handleRemoveHolding({ id })
      return new Response(result.html, {
        status: result.status,
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      })
    }

    return new Response('Not Found', { status: 404 })
  },
})

console.log(`Crypto tracker running on http://localhost:${server.port}`)
